import { NextRequest, NextResponse } from 'next/server';

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const { command, commandType, urgency, targetWorkflow } = body;

    if (!command?.trim() || !commandType) {
      return NextResponse.json({ error: 'command and commandType are required' }, { status: 400 });
    }

    const webhookUrl = process.env.ATHRX_FOUNDER_COMMAND_WEBHOOK_URL;
    const webhookToken = process.env.ATHRX_FOUNDER_COMMAND_WEBHOOK_TOKEN;
    const founderId = process.env.ATHRX_FOUNDER_ID ?? 'founder';

    const commandId = `cmd_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
    const issuedAt = new Date().toISOString();

    const orchestratorPayload = {
      command_id: commandId,
      founder_id: founderId,
      command_type: commandType,
      command_text: command.trim(),
      requested_action: commandType,
      target_workflow: targetWorkflow?.trim() || null,
      urgency: urgency ?? 'normal',
      issued_at: issuedAt,
      metadata: {
        source: 'athrx-founder-control-center',
        version: '1.2.0',
      },
    };

    if (!webhookUrl) {
      return NextResponse.json({
        id: commandId,
        status: 'not_dispatched',
        message: 'ATHRX_FOUNDER_COMMAND_WEBHOOK_URL is not configured. Set this environment variable to enable live command dispatch to ATHRX — Founder Command Orchestrator v1.',
        payload: orchestratorPayload,
      });
    }

    const headers: Record<string, string> = { 'Content-Type': 'application/json' };
    if (webhookToken) headers['Authorization'] = `Bearer ${webhookToken}`;

    const webhookRes = await fetch(webhookUrl, {
      method: 'POST',
      headers,
      body: JSON.stringify(orchestratorPayload),
    });

    if (!webhookRes.ok) {
      const body = await webhookRes.text().catch(() => '');
      return NextResponse.json({
        id: commandId,
        status: 'dispatch_failed',
        message: `Orchestrator webhook returned HTTP ${webhookRes.status}. Command not confirmed received.`,
        detail: body.slice(0, 200),
        issued_at: issuedAt,
      }, { status: 502 });
    }

    return NextResponse.json({
      id: commandId,
      status: 'dispatched',
      message: 'Command dispatched to ATHRX — Founder Command Orchestrator v1.',
      command_type: commandType,
      urgency: urgency ?? 'normal',
      target_workflow: targetWorkflow || null,
      issued_at: issuedAt,
    });
  } catch {
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

