import { NextResponse } from 'next/server';
import { createServerSupabaseClient } from '@/lib/supabase/server';
import { normalizeFile } from '@/lib/normalizers/files';
import { normalizePipelineLog } from '@/lib/normalizers/pipeline';
import { normalizeQueueItem } from '@/lib/normalizers/queue';
import { normalizeExecutionItem } from '@/lib/normalizers/execution';
import { HEALING_WORKFLOWS, AGENT_WORKFLOWS } from '@/lib/constants';
import { deriveTaskCounts } from '@/lib/helpers/taskSignals';

export const dynamic = 'force-dynamic';

export async function GET() {
  try {
    const supabase = createServerSupabaseClient();
    const today = new Date().toISOString().slice(0, 10);

    const [logsRes, queueRes, execRes, filesRes] = await Promise.allSettled([
      supabase
        .from('athrx_pipeline_logs')
        .select('id,workflow_name,stage,status,message,metadata,created_at,event_type')
        .order('created_at', { ascending: false })
        .limit(300),
      supabase
        .from('athrx_queue')
        .select('id,file_id,drive_file_id,status,attempt_count,lease_expires_at,claimed_at,updated_at')
        .order('updated_at', { ascending: false })
        .limit(300),
      supabase
        .from('athrx_execution_log')
        .select('id,execution_status,status,worker_id,claimed_at,completed_at,created_at,updated_at,error')
        .order('created_at', { ascending: false })
        .limit(200),
      supabase
        .from('athrx_files')
        .select('id,drive_file_id,file_name,mime_type,extraction_status,knowledge_status,processed_at,registered_at,updated_at')
        .order('registered_at', { ascending: false, nullsFirst: false })
        .limit(300),
    ]);

    const logs = logsRes.status === 'fulfilled' && !logsRes.value.error
      ? (logsRes.value.data ?? []).map(r => normalizePipelineLog(r))
      : [];
    const queueRaw = queueRes.status === 'fulfilled' && !queueRes.value.error
      ? (queueRes.value.data ?? []).map(normalizeQueueItem)
      : [];
    const execRaw = execRes.status === 'fulfilled' && !execRes.value.error
      ? (execRes.value.data ?? []).map(normalizeExecutionItem)
      : [];
    const filesRaw = filesRes.status === 'fulfilled' && !filesRes.value.error
      ? (filesRes.value.data ?? []).map(normalizeFile)
      : [];

    const now = Date.now();
    const queueCounts = { queued: 0, processing: 0, completed: 0, failed: 0, dead_letter: 0, stale: 0 };
    for (const q of queueRaw) {
      const s = q.status;
      if (s === 'queued' || s === 'pending') queueCounts.queued++;
      else if (s === 'processing') {
        queueCounts.processing++;
        if (q.leaseExpiresAt && new Date(q.leaseExpiresAt).getTime() < now) queueCounts.stale++;
      } else if (s === 'completed' || s === 'done' || s === 'success') queueCounts.completed++;
      else if (s === 'failed' || s === 'error') queueCounts.failed++;
      else if (s === 'dead_letter') queueCounts.dead_letter++;
    }

    const execCounts = { active: 0, completed: 0, failed: 0 };
    for (const e of execRaw) {
      const s = e.executionStatus;
      if (s === 'running' || s === 'processing' || s === 'queued') execCounts.active++;
      else if (s === 'completed' || s === 'success') execCounts.completed++;
      else if (s === 'failed' || s === 'error') execCounts.failed++;
    }

    const totalFiles = filesRaw.length;
    const filesProcessedToday = filesRaw.filter(f => {
      const d = f.processedAt || f.registeredAt;
      return d && d.startsWith(today);
    }).length;

    const unresolvedIncidents = logs.filter(l =>
      (l.severity === 'critical' || l.severity === 'high') &&
      l.status !== 'resolved' && l.status !== 'success'
    ).length;

    const healingToday = logs.filter(l => {
      const wn = l.workflowName ?? '';
      return HEALING_WORKFLOWS.some(h => wn.includes(h)) && (l.createdAt ?? '').startsWith(today);
    }).length;

    const agentActivity = logs.filter(l => {
      const wn = l.workflowName ?? '';
      return AGENT_WORKFLOWS.some(a => wn.includes(a));
    }).length;

    const taskLogs = logs.filter(l => {
      const wn = l.workflowName ?? '';
      return wn.includes('Task Execution Manager') ||
        wn.includes('Founder Command Orchestrator') ||
        wn.includes('Task Routing Agent');
    });
    const taskCounts = deriveTaskCounts(taskLogs as Parameters<typeof deriveTaskCounts>[0]);
    const pendingTasks = taskCounts.pending + taskCounts.execution_requested + taskCounts.ready_for_execution;

    const totalOps = queueCounts.queued + queueCounts.processing + queueCounts.completed + queueCounts.failed + queueCounts.dead_letter;
    const errorRate = totalOps > 0 ? ((queueCounts.failed + queueCounts.dead_letter) / totalOps) * 100 : 0;
    const execTotal = execCounts.active + execCounts.completed + execCounts.failed;
    const execErrorRate = execTotal > 0 ? (execCounts.failed / execTotal) * 100 : 0;
    const healthScore = Math.max(0, Math.min(100, Math.round(
      100 - errorRate * 1.5 - execErrorRate * 1.5 - unresolvedIncidents * 3 - queueCounts.stale * 2 - queueCounts.dead_letter * 2
    )));

    const recentEvents = logs.slice(0, 25);

    return NextResponse.json({
      kpi: {
        healthScore,
        criticalIncidents: unresolvedIncidents,
        queuedItems: queueCounts.queued,
        processingItems: queueCounts.processing,
        failedItems: queueCounts.failed,
        completedItems: queueCounts.completed,
        staleItems: queueCounts.stale,
        deadLetterItems: queueCounts.dead_letter,
        activeExecutions: execCounts.active,
        failedExecutions: execCounts.failed,
        totalFiles,
        filesProcessedToday,
        pendingTasks,
        healingActionsToday: healingToday,
        agentActivityCount: agentActivity,
      },
      recentEvents,
    });
  } catch {
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

