import { NextResponse } from 'next/server';
import { createServerSupabaseClient } from '@/lib/supabase/server';
import { normalizeQueueItem } from '@/lib/normalizers/queue';

export const dynamic = 'force-dynamic';

export async function GET() {
  try {
    const supabase = createServerSupabaseClient();
    const { data, error } = await supabase
      .from('athrx_queue')
      .select('id,file_id,drive_file_id,status,attempt_count,next_retry_at,lease_owner,lease_expires_at,claimed_at,updated_at')
      .order('updated_at', { ascending: false })
      .limit(200);

    if (error) return NextResponse.json({ items: [], stats: {}, stuck: [] });

    const items = (data ?? []).map(normalizeQueueItem);
    const stuck = items.filter(i => i.status === 'processing' && i.leaseExpiresAt && new Date(i.leaseExpiresAt) < new Date());

    const stats = { queued: 0, processing: 0, completed: 0, failed: 0, dead_letter: 0 };
    for (const i of items) {
      const s = i.status;
      if (s === 'queued' || s === 'pending') stats.queued++;
      else if (s === 'processing') stats.processing++;
      else if (s === 'completed' || s === 'done' || s === 'success') stats.completed++;
      else if (s === 'failed' || s === 'error') stats.failed++;
      else if (s === 'dead_letter') stats.dead_letter++;
    }

    return NextResponse.json({ items, stats, stuck });
  } catch {
    return NextResponse.json({ items: [], stats: {}, stuck: [] });
  }
}

