export const dynamic = 'force-dynamic';

export async function GET() {
  try {
    const supabase = createServerSupabaseClient();
    const [logRes, queueRes] = await Promise.allSettled([
      supabase
        .from('athrx_execution_log')
        .select('id,execution_status,status,worker_id,command,claimed_at,completed_at,created_at,updated_at,error')
        .order('created_at', { ascending: false })
        .limit(100),
      supabase
        .from('athrx_execution_queue')
        .select('id,execution_status,status,worker_id,claimed_at,completed_at,created_at,updated_at')
        .order('created_at', { ascending: false })
        .limit(100),
    ]);

    const log = logRes.status === 'fulfilled' && !logRes.value.error
      ? (logRes.value.data ?? []).map(normalizeExecutionItem)
      : [];
    const queue = queueRes.status === 'fulfilled' && !queueRes.value.error
      ? (queueRes.value.data ?? []).map(normalizeExecutionItem)
      : [];

    const stats = { active: 0, completed: 0, failed: 0, total: log.length };
    for (const e of log) {
      const s = e.executionStatus;
      if (s === 'running' || s === 'processing' || s === 'queued') stats.active++;
      else if (s === 'completed' || s === 'success') stats.completed++;
      else if (s === 'failed' || s === 'error') stats.failed++;
    }

    return NextResponse.json({ log, queue, stats });
  } catch {
    return NextResponse.json({ log: [], queue: [], stats: { active: 0, completed: 0, failed: 0, total: 0 } });
  }
}

