import { NextResponse } from 'next/server';
import { createServerSupabaseClient } from '@/lib/supabase/server';
import { normalizePipelineLog } from '@/lib/normalizers/pipeline';
import { HEALING_WORKFLOWS, INCIDENT_WORKFLOWS } from '@/lib/constants';

export const dynamic = 'force-dynamic';

export async function GET() {
  try {
    const supabase = createServerSupabaseClient();
    const today = new Date().toISOString().slice(0, 10);

    const { data, error } = await supabase
      .from('athrx_pipeline_logs')
      .select('id,workflow_name,stage,status,message,metadata,created_at,event_type')
      .order('created_at', { ascending: false })
      .limit(500);

    if (error) return NextResponse.json({ incidents: [], healing: [], counts: {}, hasData: false });

    const all = (data ?? []).map(r => normalizePipelineLog(r));

    const incidents = all.filter(l =>
      l.severity === 'critical' || l.severity === 'high' ||
      l.status === 'error' || l.status === 'failed' ||
      INCIDENT_WORKFLOWS.some(w => (l.workflowName ?? '').includes(w))
    );

    const healing = all.filter(l =>
      HEALING_WORKFLOWS.some(w => (l.workflowName ?? '').includes(w))
    );

    const healingToday = healing.filter(h => (h.createdAt ?? '').startsWith(today)).length;
    const critical = incidents.filter(i => i.severity === 'critical').length;
    const unresolved = incidents.filter(i => i.status !== 'resolved' && i.status !== 'success').length;

    return NextResponse.json({
      incidents: incidents.slice(0, 100),
      healing: healing.slice(0, 50),
      counts: { total: incidents.length, critical, unresolved, healingToday },
      hasData: all.length > 0,
      sourceWorkflowsActive: healing.length > 0 || incidents.length > 0,
    });
  } catch {
    return NextResponse.json({ incidents: [], healing: [], counts: {}, hasData: false });
  }
}

