import { NextResponse } from 'next/server';
import { createServerSupabaseClient } from '@/lib/supabase/server';
import { normalizeFile } from '@/lib/normalizers/files';

export const dynamic = 'force-dynamic';

export async function GET() {
  try {
    const supabase = createServerSupabaseClient();
    const today = new Date().toISOString().slice(0, 10);

    const { data, error } = await supabase
      .from('athrx_files')
      .select('id,drive_file_id,file_name,mime_type,extraction_status,knowledge_status,processed_at,registered_at,updated_at')
      .order('registered_at', { ascending: false, nullsFirst: false })
      .limit(500);

    if (error) return NextResponse.json({ files: [], stats: {}, hasData: false });

    const files = (data ?? []).map(normalizeFile);

    const extractionDist: Record<string, number> = {};
    const knowledgeDist: Record<string, number> = {};
    let processedToday = 0;
    let registeredToday = 0;
    let knowledgeIndexed = 0;

    for (const f of files) {
      const es = f.extractionStatus ?? 'unknown';
      const ks = f.knowledgeStatus ?? 'unknown';
      extractionDist[es] = (extractionDist[es] ?? 0) + 1;
      knowledgeDist[ks] = (knowledgeDist[ks] ?? 0) + 1;
      if (f.processedAt?.startsWith(today)) processedToday++;
      if (f.registeredAt?.startsWith(today)) registeredToday++;
      if (ks === 'indexed' || ks === 'synced' || ks === 'complete' || ks === 'completed') knowledgeIndexed++;
    }

    return NextResponse.json({
      files: files.slice(0, 100),
      stats: {
        total: files.length,
        processedToday,
        registeredToday,
        knowledgeIndexed,
        extractionDist: Object.entries(extractionDist).map(([name, value]) => ({ name, value })),
        knowledgeDist: Object.entries(knowledgeDist).map(([name, value]) => ({ name, value })),
      },
      hasData: files.length > 0,
    });
  } catch {
    return NextResponse.json({ files: [], stats: {}, hasData: false });
  }
}

