import { NextResponse } from 'next/server';
import { createServerSupabaseClient } from '@/lib/supabase/server';
import { normalizePipelineLog } from '@/lib/normalizers/pipeline';
import { AGENT_WORKFLOW_REGISTRY } from '@/lib/constants';

export const dynamic = 'force-dynamic';

export async function GET() {
  try {
    const supabase = createServerSupabaseClient();

    const { data, error } = await supabase
      .from('athrx_pipeline_logs')
      .select('id,workflow_name,stage,status,message,metadata,created_at,event_type')
      .order('created_at', { ascending: false })
      .limit(500);

    if (error) return NextResponse.json({
      agentLogs: [], activityByAgent: {}, latestCooSummary: null, totalAgentEvents: 0, hasData: false
    });

    const all = (data ?? []).map(r => normalizePipelineLog(r));

    const agentLogs = all.filter(l => {
      const wn = l.workflowName ?? '';
      return AGENT_WORKFLOW_REGISTRY.some(a => wn === a.fullName || wn.includes(a.matchKey));
    });

    const activityByAgent: Record<string, number> = {};
    for (const entry of AGENT_WORKFLOW_REGISTRY) {
      const count = all.filter(l => {
        const wn = l.workflowName ?? '';
        return wn === entry.fullName || wn.includes(entry.matchKey);
      }).length;
      if (count > 0) activityByAgent[entry.fullName] = count;
    }

    const cooLogs = agentLogs.filter(l => {
      const wn = l.workflowName ?? '';
      return wn.includes('COO') || wn.includes('Intelligence Engine') || wn.includes('Memory Engine');
    });
    const latestCooSummary = cooLogs[0] ?? null;

    return NextResponse.json({
      agentLogs: agentLogs.slice(0, 100),
      activityByAgent,
      latestCooSummary,
      totalAgentEvents: agentLogs.length,
      hasData: all.length > 0,
      sourceActive: agentLogs.length > 0,
    });
  } catch {
    return NextResponse.json({
      agentLogs: [], activityByAgent: {}, latestCooSummary: null, totalAgentEvents: 0, hasData: false
    });
  }
}

