import { NextResponse } from 'next/server';
import { createServerSupabaseClient } from '@/lib/supabase/server';
import { normalizePipelineLog } from '@/lib/normalizers/pipeline';
import { deriveTaskCounts } from '@/lib/helpers/taskSignals';

export const dynamic = 'force-dynamic';

export async function GET() {
  try {
    const supabase = createServerSupabaseClient();

    const { data, error } = await supabase
      .from('athrx_pipeline_logs')
      .select('id,workflow_name,stage,status,message,metadata,created_at,event_type')
      .or(
        'workflow_name.ilike.%Task Execution Manager%,' +
        'workflow_name.ilike.%Founder Command Orchestrator%,' +
        'workflow_name.ilike.%Task Routing Agent%'
      )
      .order('created_at', { ascending: false })
      .limit(400);

    if (error) return NextResponse.json({ tasks: [], counts: {}, hasData: false, sourceWorkflowsActive: false });

    const logs = (data ?? []).map(r => normalizePipelineLog(r));
    const counts = deriveTaskCounts(logs as Parameters<typeof deriveTaskCounts>[0]);

    return NextResponse.json({
      tasks: logs.slice(0, 100),
      counts,
      hasData: data !== null,
      sourceWorkflowsActive: logs.length > 0,
    });
  } catch {
    return NextResponse.json({ tasks: [], counts: {}, hasData: false, sourceWorkflowsActive: false });
  }
}

