import { NextRequest, NextResponse } from 'next/server';
import { createServerSupabaseClient } from '@/lib/supabase/server';
import { normalizePipelineLog } from '@/lib/normalizers/pipeline';

export const dynamic = 'force-dynamic';

export async function GET(req: NextRequest) {
  try {
    const supabase = createServerSupabaseClient();
    const { searchParams } = new URL(req.url);
    const workflow = searchParams.get('workflow') ?? '';
    const status = searchParams.get('status') ?? '';
    const severity = searchParams.get('severity') ?? '';
    const stage = searchParams.get('stage') ?? '';
    const from = searchParams.get('from') ?? '';
    const to = searchParams.get('to') ?? '';
    const limit = Math.min(parseInt(searchParams.get('limit') ?? '200', 10), 500);

    let query = supabase
      .from('athrx_pipeline_logs')
      .select('id,workflow_name,stage,status,message,metadata,created_at,event_type')
      .order('created_at', { ascending: false })
      .limit(limit);

    if (workflow) query = query.ilike('workflow_name', `%${workflow}%`);
    if (status) query = query.eq('status', status);
    if (stage) query = query.eq('stage', stage);
    if (from) query = query.gte('created_at', from);
    if (to) query = query.lte('created_at', to);

    const { data, error } = await query;
    if (error) return NextResponse.json({ events: [], total: 0 });

    let events = (data ?? []).map(r => normalizePipelineLog(r));
    if (severity) events = events.filter(e => e.severity === severity);

    return NextResponse.json({ events, total: events.length });
  } catch {
    return NextResponse.json({ events: [], total: 0 });
  }
}

