import type { NormalizedPipelineLog, TaskCounts } from '@/types';

export function deriveTaskCounts(logs: NormalizedPipelineLog[]): TaskCounts {
  const counts: TaskCounts = {
    pending: 0,
    completed: 0,
    blocked: 0,
    no_action_required: 0,
    duplicate_ignored: 0,
    ready_for_execution: 0,
    execution_requested: 0,
    failed: 0,
  };

  for (const l of logs) {
    const status = (l.status ?? '').toLowerCase();
    const eventType = (l.eventType ?? '').toLowerCase();
    const message = (l.message ?? '').toLowerCase();

    if (
      eventType === 'execution_requested' ||
      message.includes('execution_requested') ||
      message.includes('execution requested')
    ) {
      counts.execution_requested++;
    } else if (
      eventType === 'ready_for_execution' ||
      message.includes('ready_for_execution') ||
      message.includes('ready for execution')
    ) {
      counts.ready_for_execution++;
    } else if (
      eventType === 'no_action_required' ||
      message.includes('no_action') ||
      message.includes('no action required') ||
      status === 'no_action_required'
    ) {
      counts.no_action_required++;
    } else if (
      eventType === 'duplicate_ignored' ||
      message.includes('duplicate') ||
      message.includes('already exists') ||
      message.includes('ignored') ||
      status === 'duplicate_ignored'
    ) {
      counts.duplicate_ignored++;
    } else if (
      status === 'blocked' ||
      eventType === 'blocked' ||
      message.includes('blocked') ||
      message.includes('waiting on')
    ) {
      counts.blocked++;
    } else if (
      status === 'completed' || status === 'success' || status === 'done' ||
      eventType === 'task_completed' || eventType === 'completed'
    ) {
      counts.completed++;
    } else if (
      status === 'failed' || status === 'error' ||
      eventType === 'task_failed' || eventType === 'failed'
    ) {
      counts.failed++;
    } else if (
      status === 'pending' || status === 'queued' ||
      eventType === 'task_created' || eventType === 'task_received' ||
      message.includes('received') || message.includes('ingested')
    ) {
      counts.pending++;
    }
  }

  return counts;
}

