import type { RawPipelineLog, NormalizedPipelineLog } from '@/types';

function deriveSeverity(row: RawPipelineLog): string {
  const status = (row.status ?? '').toLowerCase();
  const message = (row.message ?? '').toLowerCase();
  const wn = (row.workflow_name ?? '').toLowerCase();
  const eventType = (row.event_type ?? '').toLowerCase();

  if (status === 'critical' || message.includes('critical') || message.includes('fatal') || eventType === 'critical') return 'critical';
  if (status === 'error' || status === 'failed' || eventType === 'error' || eventType === 'failed') {
    if (
      wn.includes('self-healing') ||
      wn.includes('incident') ||
      wn.includes('failure intelligence') ||
      wn.includes('error sink')
    ) return 'high';
    return 'high';
  }
  if (status === 'warning' || message.includes('warn') || message.includes('retry') || message.includes('stuck') || message.includes('stale')) return 'medium';
  if (status === 'info' || status === 'success' || status === 'completed' || status === 'done') return 'low';
  return 'info';
}

export function normalizePipelineLog(raw: RawPipelineLog): NormalizedPipelineLog {
  return {
    id: raw.id,
    workflowName: raw.workflow_name ?? null,
    stage: raw.stage ?? null,
    status: raw.status ?? null,
    eventType: raw.event_type ?? null,
    severity: deriveSeverity(raw),
    message: raw.message ?? null,
    metadata: (raw.metadata as Record<string, unknown>) ?? null,
    createdAt: raw.created_at ?? null,
  };
}

