import type { NormalizedPipelineLog } from '@/types';
import { AGENT_WORKFLOW_REGISTRY } from '@/lib/constants';

export function filterAgentLogs(logs: NormalizedPipelineLog[]): NormalizedPipelineLog[] {
  return logs.filter(l =>
    AGENT_WORKFLOW_REGISTRY.some(a => (l.workflowName ?? '') === a.fullName || (l.workflowName ?? '').includes(a.matchKey))
  );
}

export function groupByAgent(logs: NormalizedPipelineLog[]): Record<string, number> {
  const result: Record<string, number> = {};
  for (const entry of AGENT_WORKFLOW_REGISTRY) {
    const count = logs.filter(l => (l.workflowName ?? '') === entry.fullName || (l.workflowName ?? '').includes(entry.matchKey)).length;
    if (count > 0) result[entry.fullName] = count;
  }
  return result;
}

