import { formatDistanceToNow, format } from 'date-fns';

export function relativeTime(dateStr?: string | null): string {
  if (!dateStr) return '—';
  try { return formatDistanceToNow(new Date(dateStr), { addSuffix: true }); } catch { return '—'; }
}

export function formatDate(dateStr?: string | Date | null, fmt = 'MMM d, HH:mm'): string {
  if (!dateStr) return '—';
  try { return format(new Date(dateStr as string), fmt); } catch { return '—'; }
}

export function truncate(str?: string | null, len = 60): string {
  if (!str) return '—';
  return str.length > len ? str.slice(0, len) + '…' : str;
}

export function healthScoreColor(score: number): string {
  if (score >= 85) return 'text-emerald-400';
  if (score >= 60) return 'text-yellow-400';
  return 'text-red-400';
}

export function healthScoreLabel(score: number): string {
  if (score >= 85) return 'Healthy';
  if (score >= 60) return 'Degraded';
  return 'Critical';
}

export function severityColor(severity?: string | null): string {
  switch ((severity ?? '').toLowerCase()) {
    case 'critical': return 'text-red-400 bg-red-400/10 border-red-400/20';
    case 'high': return 'text-orange-400 bg-orange-400/10 border-orange-400/20';
    case 'medium': return 'text-yellow-400 bg-yellow-400/10 border-yellow-400/20';
    case 'low': return 'text-blue-400 bg-blue-400/10 border-blue-400/20';
    default: return 'text-slate-400 bg-slate-400/10 border-slate-400/20';
  }
}

export function statusColor(status?: string | null): string {
  switch ((status ?? '').toLowerCase()) {
    case 'completed': case 'success': case 'done': case 'resolved': case 'synced': case 'indexed':
      return 'text-emerald-400 bg-emerald-400/10 border-emerald-400/20';
    case 'processing': case 'running': case 'active': case 'claimed':
      return 'text-blue-400 bg-blue-400/10 border-blue-400/20';
    case 'failed': case 'error': case 'dead_letter':
      return 'text-red-400 bg-red-400/10 border-red-400/20';
    case 'queued': case 'pending':
      return 'text-yellow-400 bg-yellow-400/10 border-yellow-400/20';
    default:
      return 'text-slate-400 bg-slate-400/10 border-slate-400/20';
  }
}

