            <div>
              <label className="text-[10px] text-muted-foreground uppercase tracking-wider block mb-1.5">Urgency</label>
              <select
                className={cn('w-full px-2 py-1.5 text-xs bg-background border border-border rounded-lg focus:outline-none font-medium', urgencyColors[payload.urgency ?? 'normal'])}
                value={payload.urgency}
                onChange={e => setPayload(p => ({ ...p, urgency: e.target.value }))}
              >
                {URGENCY_OPTIONS.map(u => <option key={u} value={u}>{u}</option>)}
              </select>
            </div>
          </div>

          <div>
            <label className="text-[10px] text-muted-foreground uppercase tracking-wider block mb-1.5">Target Workflow</label>
            <input
              className="w-full px-2 py-1.5 text-xs bg-background border border-border rounded-lg focus:outline-none placeholder:text-muted-foreground/40"
              placeholder="e.g. ATHRX — Queue Processor v3"
              value={payload.targetWorkflow}
              onChange={e => setPayload(p => ({ ...p, targetWorkflow: e.target.value }))}
            />
          </div>

          <button
            onClick={submit}
            disabled={loading || !payload.command.trim()}
            className="w-full flex items-center justify-center gap-2 h-9 text-xs font-semibold rounded-xl bg-primary text-primary-foreground hover:bg-primary/90 disabled:opacity-40 transition-colors"
          >
