'use client';
import React from 'react';
import type { DashboardKpi } from '@/types';
import { cn } from '@/lib/utils';
import { healthScoreLabel } from '@/lib/formatters/index';
import { ShieldCheck, AlertTriangle, Clock, Zap, ListChecks, Brain } from 'lucide-react';

interface Props { kpi: DashboardKpi; loading: boolean; }
type SignalVariant = 'ok' | 'warn' | 'critical' | 'neutral';

function Signal({ icon, label, value, variant }: { icon: React.ReactNode; label: string; value: string; variant: SignalVariant }) {
  const borderBg: Record<SignalVariant, string> = {
    ok: 'border-emerald-400/20 bg-emerald-400/5',
    warn: 'border-yellow-400/20 bg-yellow-400/5',
    critical: 'border-red-400/20 bg-red-400/5',
    neutral: 'border-border bg-card/30',
  };
  const textColor: Record<SignalVariant, string> = {
    ok: 'text-emerald-400',
    warn: 'text-yellow-400',
    critical: 'text-red-400',
    neutral: 'text-muted-foreground',
  };
  return (
    <div className={cn('rounded-xl border px-4 py-3 flex items-start gap-3', borderBg[variant])}>
      <span className={cn('mt-0.5 shrink-0', textColor[variant])}>{icon}</span>
      <div>
        <div className={cn('text-xs font-semibold', textColor[variant])}>{label}</div>
        <div className="text-[11px] text-muted-foreground mt-0.5 leading-relaxed">{value}</div>
      </div>
    </div>
  );
}

export function WhatMattersNow({ kpi, loading }: Props) {
  if (loading) return (
    <div className="rounded-2xl border border-border bg-card/50 p-5">
      <div className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider mb-3">What Matters Now</div>
      <div className="text-xs text-muted-foreground/40">Fetching system state...</div>
    </div>
  );

  const healthLabel = healthScoreLabel(kpi.healthScore);
  const healthVariant: SignalVariant = kpi.healthScore >= 85 ? 'ok' : kpi.healthScore >= 60 ? 'warn' : 'critical';

  const incidentVariant: SignalVariant = kpi.criticalIncidents === 0 ? 'ok' : kpi.criticalIncidents <= 3 ? 'warn' : 'critical';
  const incidentMsg = kpi.criticalIncidents === 0
    ? 'No unresolved critical incidents in log window.'
    : `${kpi.criticalIncidents} unresolved incident${kpi.criticalIncidents > 1 ? 's' : ''} require attention.`;

  const queueVariant: SignalVariant = kpi.failedItems === 0 && kpi.staleItems === 0 && kpi.deadLetterItems === 0
    ? 'ok'
    : kpi.deadLetterItems > 0 || kpi.failedItems > 10 || kpi.staleItems > 5
    ? 'critical'
    : 'warn';
  const queueParts: string[] = [];
  if (kpi.staleItems > 0) queueParts.push(`${kpi.staleItems} stale lease${kpi.staleItems > 1 ? 's' : ''} (processing expired)`);
  if (kpi.deadLetterItems > 0) queueParts.push(`${kpi.deadLetterItems} dead-letter item${kpi.deadLetterItems > 1 ? 's' : ''} require manual review`);
  if (kpi.failedItems > 0) queueParts.push(`${kpi.failedItems} failed`);
  const queueMsg = queueParts.length > 0 ? queueParts.join(' · ') : 'Queue flowing normally.';

  const execVariant: SignalVariant = kpi.failedExecutions === 0 ? 'ok' : kpi.failedExecutions > 5 ? 'critical' : 'warn';
  const execMsg = kpi.failedExecutions === 0
    ? `${kpi.activeExecutions} active execution${kpi.activeExecutions !== 1 ? 's' : ''}. Execution layer clean.`
    : `${kpi.failedExecutions} failed execution${kpi.failedExecutions > 1 ? 's' : ''}. Review execution log.`;

  const taskVariant: SignalVariant = kpi.pendingTasks === 0 ? 'neutral' : kpi.pendingTasks > 10 ? 'warn' : 'neutral';
  const taskMsg = kpi.pendingTasks === 0
    ? 'No pending task signals from Orchestrator or Task Manager.'
    : `${kpi.pendingTasks} task signal${kpi.pendingTasks > 1 ? 's' : ''} pending or queued for execution.`;

  const kbVariant: SignalVariant = kpi.filesProcessedToday > 0 ? 'ok' : kpi.totalFiles === 0 ? 'neutral' : 'neutral';
  const kbMsg = kpi.totalFiles === 0
    ? 'No files registered in athrx_files yet.'
    : kpi.filesProcessedToday === 0
    ? `${kpi.totalFiles} files indexed. None processed in current period.`
    : `${kpi.filesProcessedToday} of ${kpi.totalFiles} files processed today.`;

  return (
    <div className="rounded-2xl border border-border bg-card/50 p-5">
      <div className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider mb-4">What Matters Now</div>
      <div className="grid grid-cols-2 lg:grid-cols-3 gap-3">
        <Signal icon={<ShieldCheck className="h-3.5 w-3.5" />}
          label={`System ${healthLabel} — ${kpi.healthScore}/100`}
          value={kpi.healthScore >= 85 ? 'All systems nominal.' : kpi.healthScore >= 60 ? 'Performance degraded. Review incidents and queue.' : 'Critical degradation. Immediate attention required.'}
          variant={healthVariant} />
        <Signal icon={<AlertTriangle className="h-3.5 w-3.5" />}
          label={`${kpi.criticalIncidents} Open Incident${kpi.criticalIncidents !== 1 ? 's' : ''}`}
          value={incidentMsg} variant={incidentVariant} />
        <Signal icon={<Clock className="h-3.5 w-3.5" />}
          label="Queue State"
          value={queueMsg} variant={queueVariant} />
        <Signal icon={<Zap className="h-3.5 w-3.5" />}
          label="Execution Layer"
          value={execMsg} variant={execVariant} />
        <Signal icon={<ListChecks className="h-3.5 w-3.5" />}
          label={`${kpi.pendingTasks} Pending Task Signal${kpi.pendingTasks !== 1 ? 's' : ''}`}
          value={taskMsg} variant={taskVariant} />
        <Signal icon={<Brain className="h-3.5 w-3.5" />}
          label="Knowledge State"
          value={kbMsg} variant={kbVariant} />
      </div>
    </div>
  );
}

