'use client';
import React from 'react';
import { useApiData } from '@/hooks/useApiData';
import { REFRESH_INTERVALS } from '@/lib/constants';
import { SectionHeader } from '@/components/ui-custom/SectionHeader';
import { KpiCard } from '@/components/cards/KpiCard';
import { RecentEventsTable } from '@/components/tables/RecentEventsTable';
import type { NormalizedPipelineLog, TaskCounts } from '@/types';
import { CheckSquare, Clock, AlertCircle, XCircle, MinusCircle, Copy, Zap, PlayCircle } from 'lucide-react';

interface TaskData {
  tasks: NormalizedPipelineLog[];
  counts: TaskCounts;
  hasData: boolean;
  sourceWorkflowsActive: boolean;
}

const DEFAULT_COUNTS: TaskCounts = {
  pending: 0, completed: 0, blocked: 0,
  no_action_required: 0, duplicate_ignored: 0,
  ready_for_execution: 0, execution_requested: 0, failed: 0,
};

const DEFAULT: TaskData = {
  tasks: [], counts: DEFAULT_COUNTS, hasData: false, sourceWorkflowsActive: false,
};

export function TasksPage() {
  const { data, loading, refresh, lastRefresh } = useApiData<TaskData>(
    '/api/dashboard/tasks', REFRESH_INTERVALS.tasks, DEFAULT
  );
  const { tasks, counts, hasData, sourceWorkflowsActive } = data;

  const emptyMessage = !hasData
    ? 'Unable to read pipeline logs. Verify Supabase connection.'
    : !sourceWorkflowsActive
    ? 'Task Execution Manager, Founder Command Orchestrator, and Task Routing Agent have not emitted log signals yet.'
    : 'No task signals classified in current log window.';

  return (
    <div className="space-y-5">
      <SectionHeader title="Founder Tasks" subtitle="Task Execution Manager · Command Orchestrator · Routing Agent" onRefresh={refresh} lastRefresh={lastRefresh} />

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        <KpiCard label="Pending" value={counts.pending} loading={loading} icon={<Clock className="h-4 w-4" />} variant={counts.pending > 0 ? 'warning' : 'neutral'} />
        <KpiCard label="Ready for Exec" value={counts.ready_for_execution} loading={loading} icon={<PlayCircle className="h-4 w-4" />} variant={counts.ready_for_execution > 0 ? 'warning' : 'neutral'} />
        <KpiCard label="Exec Requested" value={counts.execution_requested} loading={loading} icon={<Zap className="h-4 w-4" />} variant={counts.execution_requested > 0 ? 'neutral' : 'neutral'} />
        <KpiCard label="Completed" value={counts.completed} loading={loading} icon={<CheckSquare className="h-4 w-4" />} variant="success" />
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        <KpiCard label="Blocked" value={counts.blocked} loading={loading} icon={<XCircle className="h-4 w-4" />} variant={counts.blocked > 0 ? 'error' : 'neutral'} />
        <KpiCard label="No Action Req." value={counts.no_action_required} loading={loading} icon={<MinusCircle className="h-4 w-4" />} variant="neutral" />
        <KpiCard label="Duplicate / Skip" value={counts.duplicate_ignored} loading={loading} icon={<Copy className="h-4 w-4" />} variant="neutral" />
        <KpiCard label="Failed" value={counts.failed} loading={loading} icon={<AlertCircle className="h-4 w-4" />} variant={counts.failed > 0 ? 'error' : 'neutral'} />
      </div>

      {tasks.length === 0 && !loading ? (
        <div className="rounded-2xl border border-border bg-card p-10 flex flex-col items-center justify-center gap-3">
          <CheckSquare className="h-8 w-8 text-muted-foreground/20" />
          <p className="text-sm text-muted-foreground text-center max-w-md">{emptyMessage}</p>
        </div>
      ) : (
        <div className="rounded-2xl border border-border bg-card">
          <div className="p-4 border-b border-border">
            <span className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Task Activity Log</span>
          </div>
          <RecentEventsTable data={tasks} loading={loading} />
        </div>
      )}
    </div>
  );
}

