'use client';
import React from 'react';
import { useApiData } from '@/hooks/useApiData';
import { REFRESH_INTERVALS, AGENT_WORKFLOW_REGISTRY } from '@/lib/constants';
import { SectionHeader } from '@/components/ui-custom/SectionHeader';
import { KpiCard } from '@/components/cards/KpiCard';
import { RecentEventsTable } from '@/components/tables/RecentEventsTable';
import type { NormalizedPipelineLog } from '@/types';
import { Bot, Brain, Activity } from 'lucide-react';

interface AgentsData {
  agentLogs: NormalizedPipelineLog[];
  activityByAgent: Record<string, number>;
  latestCooSummary: NormalizedPipelineLog | null;
  totalAgentEvents: number;
  hasData: boolean;
  sourceActive: boolean;
}

const DEFAULT: AgentsData = {
  agentLogs: [], activityByAgent: {}, latestCooSummary: null,
  totalAgentEvents: 0, hasData: false, sourceActive: false,
};

export function AgentsPage() {
  const { data, loading, refresh, lastRefresh } = useApiData<AgentsData>(
    '/api/dashboard/agents', REFRESH_INTERVALS.agents, DEFAULT
  );
  const { agentLogs, activityByAgent, latestCooSummary, totalAgentEvents, hasData, sourceActive } = data;

  const emptyMessage = !hasData
    ? 'Unable to read pipeline logs. Check Supabase configuration.'
    : !sourceActive
    ? 'No ATHRX agent workflows have emitted pipeline log signals yet.'
    : 'No agent events in current log window.';

  return (
    <div className="space-y-5">
      <SectionHeader title="Agents & COO" subtitle="Agent Registry · COO Intelligence · Orchestration" onRefresh={refresh} lastRefresh={lastRefresh} />
      <div className="grid grid-cols-2 lg:grid-cols-3 gap-3">
        <KpiCard label="Registered Agents" value={AGENT_WORKFLOW_REGISTRY.length} loading={false} icon={<Bot className="h-4 w-4" />} />
        <KpiCard label="Agent Events" value={totalAgentEvents} loading={loading} icon={<Activity className="h-4 w-4" />} />
        <KpiCard label="COO Signal Present" value={latestCooSummary ? 1 : 0} loading={loading} icon={<Brain className="h-4 w-4" />} variant={latestCooSummary ? 'success' : 'neutral'} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div className="rounded-2xl border border-border bg-card p-4">
          <div className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider mb-3">Agent Registry</div>
          <div className="space-y-1">
            {AGENT_WORKFLOW_REGISTRY.map(agent => {
              const count = activityByAgent[agent.fullName] ?? 0;
              return (
                <div key={agent.fullName} className="flex items-center justify-between py-1.5 border-b border-border/30 last:border-0">
                  <div className="flex items-center gap-2">
                    <span className={`h-1.5 w-1.5 rounded-full shrink-0 ${count > 0 ? 'bg-emerald-400' : 'bg-muted-foreground/30'}`} />
                    <span className="text-[11px] text-muted-foreground truncate max-w-[240px]">{agent.fullName}</span>
                  </div>
                  {count > 0 && (
                    <span className="text-[10px] text-primary/70 shrink-0 tabular-nums">{count} events</span>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        <div className="rounded-2xl border border-border bg-card p-4">
          <div className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider mb-3">Latest COO Signal</div>
          {latestCooSummary ? (
            <div className="space-y-2">
              <div className="text-[10px] text-muted-foreground font-medium">{latestCooSummary.workflowName}</div>
              <div className="text-xs text-muted-foreground/80 bg-background/60 rounded-xl p-3 border border-border leading-relaxed">
                {latestCooSummary.message ?? 'No message content in this log entry.'}
              </div>
              <div className="text-[10px] text-muted-foreground/40 font-mono">{latestCooSummary.createdAt}</div>
            </div>
          ) : (
            <div className="flex items-center justify-center h-32">
              <p className="text-xs text-muted-foreground/50 text-center px-4">
                {!hasData ? 'Awaiting connection to pipeline logs.' : 'No COO agent signals in current log window.'}
              </p>
            </div>
          )}
        </div>
      </div>

      {agentLogs.length > 0 ? (
        <div className="rounded-2xl border border-border bg-card">
          <div className="p-4 border-b border-border flex items-center justify-between">
            <span className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Agent Activity Log</span>
            <span className="text-[10px] text-muted-foreground">{agentLogs.length} events</span>
          </div>
          <RecentEventsTable data={agentLogs} loading={loading} />
        </div>
      ) : !loading && (
        <div className="rounded-2xl border border-border bg-card p-8 flex items-center justify-center">
          <p className="text-xs text-muted-foreground text-center max-w-md">{emptyMessage}</p>
        </div>
      )}
    </div>
  );
}

