'use client';
import React, { useState } from 'react';
import { useApiData } from '@/hooks/useApiData';
import { REFRESH_INTERVALS } from '@/lib/constants';
import { RecentEventsTable } from '@/components/tables/RecentEventsTable';
import { SectionHeader } from '@/components/ui-custom/SectionHeader';
import type { NormalizedPipelineLog } from '@/types';
import { Search } from 'lucide-react';

interface EventsData { events: NormalizedPipelineLog[]; total: number; }
const DEFAULT: EventsData = { events: [], total: 0 };

export function EventStreamPage() {
  const [workflowFilter, setWorkflowFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [severityFilter, setSeverityFilter] = useState('');
  const [stageFilter, setStageFilter] = useState('');

  const params = new URLSearchParams({ limit: '300' });
  if (workflowFilter) params.set('workflow', workflowFilter);
  if (statusFilter) params.set('status', statusFilter);
  if (severityFilter) params.set('severity', severityFilter);
  if (stageFilter) params.set('stage', stageFilter);

  const url = `/api/dashboard/events?${params.toString()}`;
  const { data, loading, refresh, lastRefresh } = useApiData<EventsData>(url, REFRESH_INTERVALS.events, DEFAULT);
  const { events, total } = data;

  const statuses = ['error', 'success', 'pending', 'completed', 'failed', 'processing', 'no_action_required', 'blocked'];
  const severities = ['critical', 'high', 'medium', 'low', 'info'];

  return (
    <div className="space-y-5">
      <SectionHeader title="Event Stream" subtitle="athrx_pipeline_logs — unified view" onRefresh={refresh} lastRefresh={lastRefresh} />

      <div className="flex flex-wrap gap-2 items-center">
        <div className="relative">
          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3 w-3 text-muted-foreground" />
          <input
            className="pl-8 pr-3 py-1.5 text-xs bg-card border border-border rounded-lg w-56 focus:outline-none focus:ring-1 focus:ring-primary"
            placeholder="Filter workflow..."
            value={workflowFilter}
            onChange={e => setWorkflowFilter(e.target.value)}
          />
        </div>
        <input
          className="px-3 py-1.5 text-xs bg-card border border-border rounded-lg w-36 focus:outline-none focus:ring-1 focus:ring-primary"
          placeholder="Stage filter..."
          value={stageFilter}
          onChange={e => setStageFilter(e.target.value)}
        />
        <select
          className="px-3 py-1.5 text-xs bg-card border border-border rounded-lg focus:outline-none"
          value={statusFilter}
          onChange={e => setStatusFilter(e.target.value)}
        >
          <option value="">All statuses</option>
          {statuses.map(s => <option key={s} value={s}>{s}</option>)}
        </select>
        <select
          className="px-3 py-1.5 text-xs bg-card border border-border rounded-lg focus:outline-none"
          value={severityFilter}
          onChange={e => setSeverityFilter(e.target.value)}
        >
          <option value="">All severities</option>
          {severities.map(s => <option key={s} value={s}>{s}</option>)}
        </select>
        <span className="ml-auto text-[11px] text-muted-foreground tabular-nums">{total} events</span>
      </div>

      <div className="rounded-2xl border border-border bg-card">
        <RecentEventsTable data={events} loading={loading} maxRows={300} />
      </div>
    </div>
  );
}

