'use client';
import React from 'react';
import { cn } from '@/lib/utils';

interface Props {
  label: string;
  value?: number | null;
  loading?: boolean;
  icon?: React.ReactNode;
  subtitle?: string;
  variant?: 'success' | 'error' | 'warning' | 'neutral';
}

const VARIANT_COLORS: Record<string, string> = {
  success: 'text-emerald-400',
  error: 'text-red-400',
  warning: 'text-yellow-400',
  neutral: 'text-blue-400',
};

export function KpiCard({ label, value, loading, icon, subtitle, variant = 'neutral' }: Props) {
  const color = VARIANT_COLORS[variant];
  return (
    <div className="rounded-2xl border border-border bg-card p-4 flex flex-col gap-2 hover:border-border/80 transition-colors">
      <div className="flex items-center justify-between">
        <span className="text-[10px] text-muted-foreground font-medium uppercase tracking-wide">{label}</span>
        {icon && <span className={cn('opacity-50', color)}>{icon}</span>}
      </div>
      <div className={cn('text-2xl font-bold tracking-tight tabular-nums', loading ? 'text-muted-foreground/20' : color)}>
        {loading ? '—' : (value ?? 0).toLocaleString()}
      </div>
      {subtitle && <div className="text-[10px] text-muted-foreground">{subtitle}</div>}
    </div>
  );
}

