'use client';
import React from 'react';
import type { NormalizedPipelineLog } from '@/types';
import { relativeTime, truncate } from '@/lib/formatters/index';
import { StatusBadge } from '@/components/ui-custom/StatusBadge';
import { SeverityBadge } from '@/components/ui-custom/SeverityBadge';

interface Props {
  data: NormalizedPipelineLog[];
  loading?: boolean;
  maxRows?: number;
}

export function RecentEventsTable({ data, loading, maxRows = 50 }: Props) {
  const rows = data.slice(0, maxRows);
  if (loading) return <div className="p-6 text-center text-xs text-muted-foreground/50">Loading events...</div>;
  if (!rows.length) return <div className="p-6 text-center text-xs text-muted-foreground/50">No events in this view.</div>;

  return (
    <div className="overflow-x-auto">
      <table className="w-full text-xs">
        <thead>
          <tr className="border-b border-border">
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide whitespace-nowrap">Time</th>
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide">Workflow</th>
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide">Stage</th>
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide">Status</th>
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide">Sev</th>
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide">Message</th>
          </tr>
        </thead>
        <tbody>
          {rows.map(row => (
            <tr key={row.id} className="border-b border-border/30 hover:bg-accent/20 transition-colors">
              <td className="px-4 py-2 text-muted-foreground/60 font-mono whitespace-nowrap">{relativeTime(row.createdAt)}</td>
              <td className="px-4 py-2 max-w-[200px] truncate text-foreground/80" title={row.workflowName ?? ''}>{truncate(row.workflowName, 32) || '—'}</td>
              <td className="px-4 py-2 text-muted-foreground/60">{row.stage || '—'}</td>
              <td className="px-4 py-2"><StatusBadge status={row.status} /></td>
              <td className="px-4 py-2"><SeverityBadge severity={row.severity} /></td>
              <td className="px-4 py-2 text-muted-foreground/60 max-w-[300px] truncate" title={row.message ?? ''}>{truncate(row.message, 60) || '—'}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

