'use client';
import React from 'react';
import type { NormalizedFileItem } from '@/types';
import { relativeTime, truncate } from '@/lib/formatters/index';
import { StatusBadge } from '@/components/ui-custom/StatusBadge';
import { CheckCircle2, Circle } from 'lucide-react';

interface Props { data: NormalizedFileItem[]; loading?: boolean; }

export function FilesTable({ data, loading }: Props) {
  if (loading) return <div className="p-6 text-center text-xs text-muted-foreground/50">Loading...</div>;
  if (!data.length) return <div className="p-6 text-center text-xs text-muted-foreground/50">No files in athrx_files.</div>;

  return (
    <div className="overflow-x-auto">
      <table className="w-full text-xs">
        <thead>
          <tr className="border-b border-border">
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide">Registered</th>
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide">Name</th>
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide">Extraction</th>
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide">Knowledge</th>
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide">Summary</th>
            <th className="text-left px-4 py-2.5 text-[10px] text-muted-foreground font-medium uppercase tracking-wide">Processed</th>
          </tr>
        </thead>
        <tbody>
          {data.map(row => (
            <tr key={row.id} className="border-b border-border/30 hover:bg-accent/20 transition-colors">
              <td className="px-4 py-2 text-muted-foreground/60 font-mono whitespace-nowrap">{relativeTime(row.registeredAt)}</td>
              <td className="px-4 py-2 text-foreground/80 max-w-[200px] truncate" title={row.displayName}>{truncate(row.displayName, 36)}</td>
              <td className="px-4 py-2"><StatusBadge status={row.extractionStatus} /></td>
              <td className="px-4 py-2"><StatusBadge status={row.knowledgeStatus} /></td>
              <td className="px-4 py-2">{row.hasSummary ? <CheckCircle2 className="h-3.5 w-3.5 text-emerald-400" /> : <Circle className="h-3.5 w-3.5 text-muted-foreground/30" />}</td>
              <td className="px-4 py-2 text-muted-foreground/60 font-mono whitespace-nowrap">{relativeTime(row.processedAt)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

