'use client';
import React, { useMemo } from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import type { NormalizedPipelineLog } from '@/types';
import { format } from 'date-fns';

interface Props { data: NormalizedPipelineLog[]; title?: string; }

export function ThroughputChart({ data, title }: Props) {
  const chartData = useMemo(() => {
    const buckets: Record<string, number> = {};
    for (const row of data) {
      if (!row.createdAt) continue;
      try {
        const key = format(new Date(row.createdAt), 'HH:mm');
        buckets[key] = (buckets[key] ?? 0) + 1;
      } catch {}
    }
    return Object.entries(buckets).sort(([a], [b]) => a.localeCompare(b)).slice(-20).map(([time, count]) => ({ time, count }));
  }, [data]);

  return (
    <div className="rounded-2xl border border-border bg-card p-4">
      {title && <div className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider mb-3">{title}</div>}
      {!chartData.length ? (
        <div className="h-40 flex items-center justify-center text-xs text-muted-foreground/50">No data available</div>
      ) : (
        <ResponsiveContainer width="100%" height={160}>
          <AreaChart data={chartData} margin={{ top: 4, right: 4, bottom: 0, left: -20 }}>
            <defs>
              <linearGradient id="tpGrad" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="hsl(210 100% 56%)" stopOpacity={0.25} />
                <stop offset="95%" stopColor="hsl(210 100% 56%)" stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="hsl(222 14% 12%)" />
            <XAxis dataKey="time" tick={{ fill: 'hsl(215 16% 40%)', fontSize: 10 }} axisLine={false} tickLine={false} />
            <YAxis tick={{ fill: 'hsl(215 16% 40%)', fontSize: 10 }} axisLine={false} tickLine={false} />
            <Tooltip contentStyle={{ background: 'hsl(222 18% 9%)', border: '1px solid hsl(222 14% 14%)', borderRadius: 8, fontSize: 11 }} labelStyle={{ color: 'hsl(210 20% 80%)' }} />
            <Area type="monotone" dataKey="count" stroke="hsl(210 100% 56%)" fill="url(#tpGrad)" strokeWidth={1.5} dot={false} />
          </AreaChart>
        </ResponsiveContainer>
      )}
    </div>
  );
}

files.components/charts/FailureTrendChart.tsx:
'use client';
import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import type { NormalizedPipelineLog } from '@/types';
import { format } from 'date-fns';

interface Props { data: NormalizedPipelineLog[]; color?: string; }

export function FailureTrendChart({ data, color = 'hsl(0 72% 51%)' }: Props) {
  const chartData = useMemo(() => {
    const buckets: Record<string, number> = {};
    for (const row of data) {
      if (!row.createdAt) continue;
      try {
        const key = format(new Date(row.createdAt), 'MMM d HH:mm');
        buckets[key] = (buckets[key] ?? 0) + 1;
      } catch {}
    }
    return Object.entries(buckets).sort(([a], [b]) => a.localeCompare(b)).slice(-14).map(([time, count]) => ({ time, count }));
  }, [data]);

  if (!chartData.length) return <div className="h-36 flex items-center justify-center text-xs text-muted-foreground/50">No data</div>;

  return (
    <ResponsiveContainer width="100%" height={140}>
      <BarChart data={chartData} margin={{ top: 4, right: 4, bottom: 0, left: -20 }}>
        <CartesianGrid strokeDasharray="3 3" stroke="hsl(222 14% 12%)" />
        <XAxis dataKey="time" tick={{ fill: 'hsl(215 16% 40%)', fontSize: 9 }} axisLine={false} tickLine={false} />
        <YAxis tick={{ fill: 'hsl(215 16% 40%)', fontSize: 10 }} axisLine={false} tickLine={false} />
        <Tooltip contentStyle={{ background: 'hsl(222 18% 9%)', border: '1px solid hsl(222 14% 14%)', borderRadius: 8, fontSize: 11 }} />
        <Bar dataKey="count" fill={color} radius={[3, 3, 0, 0]} opacity={0.85} />
      </BarChart>
    </ResponsiveContainer>
  );
}

