'use client';
import React from 'react';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, Legend } from 'recharts';

const COLORS = ['hsl(210 100% 56%)', 'hsl(150 60% 48%)', 'hsl(45 100% 52%)', 'hsl(0 72% 51%)', 'hsl(280 60% 60%)', 'hsl(200 60% 55%)'];

export function DistributionChart({ data }: { data: { name: string; value: number }[] }) {
  if (!data.length) return <div className="h-40 flex items-center justify-center text-xs text-muted-foreground/50">No distribution data</div>;

  return (
    <ResponsiveContainer width="100%" height={160}>
      <PieChart>
        <Pie data={data} cx="50%" cy="50%" innerRadius={38} outerRadius={60} paddingAngle={2} dataKey="value">
          {data.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} stroke="transparent" />)}
        </Pie>
        <Tooltip contentStyle={{ background: 'hsl(222 18% 9%)', border: '1px solid hsl(222 14% 14%)', borderRadius: 8, fontSize: 11 }} />
        <Legend wrapperStyle={{ fontSize: 10, color: 'hsl(215 16% 47%)' }} />
      </PieChart>
    </ResponsiveContainer>
  );
}

files.components/ui-custom/SectionHeader.tsx:
'use client';
import React from 'react';
import { RefreshCw } from 'lucide-react';
import { relativeTime } from '@/lib/formatters/index';

interface Props {
  title: string;
  subtitle?: string;
  onRefresh?: () => void;
  lastRefresh?: Date | null;
}

export function SectionHeader({ title, subtitle, onRefresh, lastRefresh }: Props) {
  return (
    <div className="flex items-end justify-between mb-1">
      <div>
        <h1 className="text-base font-bold tracking-tight text-foreground">{title}</h1>
        {subtitle && <p className="text-[11px] text-muted-foreground mt-0.5">{subtitle}</p>}
      </div>
      {onRefresh && (
        <div className="flex items-center gap-2">
          {lastRefresh && (
            <span className="text-[10px] text-muted-foreground/40 tabular-nums">
              refreshed {relativeTime(lastRefresh.toISOString())}
            </span>
          )}
          <button
            onClick={onRefresh}
            className="flex items-center gap-1.5 px-2.5 h-7 text-[11px] text-muted-foreground hover:text-foreground border border-border rounded-lg hover:bg-accent transition-colors"
          >
            <RefreshCw className="h-3 w-3" /> Refresh
          </button>
        </div>
      )}
    </div>
  );
}

