'use client';
import React from 'react';
import { statusColor } from '@/lib/formatters/index';
import { cn } from '@/lib/utils';

export function StatusBadge({ status }: { status?: string | null }) {
  if (!status) return <span className="text-muted-foreground/40">—</span>;
  return (
    <span className={cn('inline-flex px-1.5 py-0.5 rounded border text-[9px] font-semibold uppercase tracking-wider', statusColor(status))}>
      {status}
    </span>
  );
}

