'use client';
import React from 'react';
import { severityColor } from '@/lib/formatters/index';
import { cn } from '@/lib/utils';

export function SeverityBadge({ severity }: { severity?: string | null }) {
  if (!severity || severity === 'info') return <span className="text-muted-foreground/30 text-[9px]">info</span>;
  return (
    <span className={cn('inline-flex px-1.5 py-0.5 rounded border text-[9px] font-semibold uppercase tracking-wider', severityColor(severity))}>
      {severity}
    </span>
  );
}
